#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int n,w,a[1003],dp[10004][1003];
int main(){
    scanf("%d%d",&n,&w);
    for(int i=1;i<=n;i++)
    	scanf("%d",&a[i]);
    for(int i=1;i<=n;i++)
    	dp[0][i]=1;
    for(int i=1;i<=w;i++)
    	for(int j=1;j<=n;j++)
    		if(i-a[j]>=0)
    			dp[i][j]=dp[i-a[j]][j]+dp[i][j-1],dp[i][j]%=mod;
    		else
				dp[i][j]=dp[i][j-1];
	printf("%d",dp[w][n]); 
    return 0;
}
